changeSet.sql:
CREATE TABLE IF NOT EXISTS fin_account_types ( id Integer not null, name VARCHAR(50) UNIQUE NOT NULL, description TEXT, CONSTRAINT app_fin_account_types_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS fin_account_types_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY fin_account_types.id;
CREATE TABLE IF NOT EXISTS fin_accounts ( id Integer not null, m_account_id BIGINT not null, created_by character varying(255) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(255) , last_modified_date timestamp(6) without time zone, deleted_by character varying(255) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false, serial_id VARCHAR(50) UNIQUE NOT NULL, name VARCHAR(100) NOT NULL, description TEXT, parent_serial_id VARCHAR(50) REFERENCES fin_accounts(serial_id), account_type_id INTEGER , account_category VARCHAR(50), balance DECIMAL(15,2) DEFAULT 0, currency_id integer , is_active BOOLEAN DEFAULT TRUE, is_debit BOOLEAN DEFAULT FALSE, is_cash_account BOOLEAN DEFAULT FALSE, is_bank_account BOOLEAN DEFAULT FALSE, is_control_account BOOLEAN DEFAULT FALSE, CONSTRAINT app_fin_accounts_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS fin_accounts_id_seq INCREMENT 1 START 38 MINVALUE 1 MAXVALUE 100000000 CACHE 1 OWNED BY fin_accounts.id;
-- Initial data INSERT INTO fin_account_types (id,name, description) VALUES (1,'Asset', 'Resources owned by the business'), (2,'Liability', 'Debts owed by the business'), (3,'Equity', 'Owner''s interest in the business'), (4,'Revenue', 'Income earned by the business'), (5,'Expense', 'Costs incurred by the business');
